// =============================================================
//  llm/index.js
//  按用户设置分发到 mock / openai / deepseek / claude
//  没配置 api_key → 强制回落到 mock
// =============================================================

const mock = require('./mock')
const openai = require('./openai')
const claude = require('./claude')

async function generate({ settings, messages }) {
  const provider = settings?.provider || 'mock'
  const apiKey   = settings?.api_key || ''

  // 没 key 一律走 mock（教学版即开即用）
  if (provider === 'mock' || !apiKey) {
    return await mock.chat({ messages })
  }

  const args = {
    provider,
    apiKey,
    apiBase:      settings.api_base || '',
    model:        settings.model || '',
    systemPrompt: settings.system_prompt || '',
    messages
  }

  if (provider === 'openai' || provider === 'deepseek') {
    return await openai.chat(args)
  }
  if (provider === 'claude') {
    return await claude.chat(args)
  }

  // 未知 provider → mock 兜底
  return await mock.chat({ messages })
}

module.exports = { generate }

// =============================================================
//  llm/mock.js
//  纯本地"AI"——按关键词匹配几条回复
//  教学版默认 provider，确保学生没 API key 也能跑通
// =============================================================

const RULES = [
  { match: /^你好|^hi$|^hello/i,
    reply: '你好！我是教学版 chatbox 的内置 Mock 助手。\n\n要切换成真实大模型，去**设置**页填一个 OpenAI / DeepSeek / Claude 的 API key。' },

  { match: /(谁|你是).*(写|做|开发)/,
    reply: '我是给本教程演示用的 mock 回复器，**没有真模型**。在设置里配置 provider 和 api_key 之后，这里会替换成真正的 AI。' },

  { match: /api[\s_-]?key|怎么配|怎么用|设置/i,
    reply: '点左下角设置按钮 ⚙️，选 provider（openai / deepseek / claude），填上你的 api_key，回到聊天页就接真模型了。' },

  { match: /markdown|代码|code/i,
    reply: '消息支持 Markdown：\n\n```js\nconst greeting = "hello"\nconsole.log(greeting)\n```\n\n- 列表也 OK\n- *斜体* / **加粗** / `行内代码`' },

  { match: /笑话|讲个笑话|joke/i,
    reply: '程序员的浪漫：\n\n> 「Hello, World!」\n\n（讲完了。）' },

  { match: /.+/, // 兜底
    reply: '我是 mock 助手，只能识别几条预置规则。试试问我「你好」「markdown」「笑话」「api key 怎么配」。' }
]

async function chat({ messages /* [{role, content}] */ }) {
  const last = messages[messages.length - 1]
  const userText = last?.content || ''
  const rule = RULES.find(r => r.match.test(userText)) || RULES[RULES.length - 1]
  // 模拟一点"思考"延迟，让 loading 状态可见
  await new Promise(r => setTimeout(r, 350 + Math.random() * 400))
  return rule.reply
}

module.exports = { chat }

// =============================================================
//  llm/openai.js
//  调用 OpenAI 兼容协议（OpenAI / DeepSeek / 任何走 OpenAI 协议的网关）
//  使用 Node 18+ 内置 fetch，不引第三方依赖
// =============================================================

const DEFAULTS = {
  openai:   { base: 'https://api.openai.com/v1',     model: 'gpt-4o-mini' },
  deepseek: { base: 'https://api.deepseek.com/v1',   model: 'deepseek-chat' }
}

async function chat({ provider, apiKey, apiBase, model, systemPrompt, messages }) {
  const def = DEFAULTS[provider] || DEFAULTS.openai
  const base = (apiBase || def.base).replace(/\/$/, '')
  const useModel = model || def.model

  const body = {
    model: useModel,
    messages: [
      ...(systemPrompt ? [{ role: 'system', content: systemPrompt }] : []),
      ...messages
    ]
  }

  const resp = await fetch(`${base}/chat/completions`, {
    method: 'POST',
    headers: {
      'Content-Type':  'application/json',
      'Authorization': `Bearer ${apiKey}`
    },
    body: JSON.stringify(body)
  })

  if (!resp.ok) {
    const text = await resp.text()
    throw new Error(`${provider} ${resp.status}: ${text.slice(0, 200)}`)
  }
  const json = await resp.json()
  return json.choices?.[0]?.message?.content || '(空回复)'
}

module.exports = { chat }

// =============================================================
//  llm/claude.js
//  调用 Anthropic Claude messages API
// =============================================================

const DEFAULT_BASE  = 'https://api.anthropic.com/v1'
const DEFAULT_MODEL = 'claude-sonnet-4-5'

async function chat({ apiKey, apiBase, model, systemPrompt, messages }) {
  const base = (apiBase || DEFAULT_BASE).replace(/\/$/, '')
  const useModel = model || DEFAULT_MODEL

  const body = {
    model: useModel,
    max_tokens: 1024,
    ...(systemPrompt ? { system: systemPrompt } : {}),
    messages: messages.map(m => ({ role: m.role, content: m.content }))
  }

  const resp = await fetch(`${base}/messages`, {
    method: 'POST',
    headers: {
      'Content-Type':      'application/json',
      'x-api-key':         apiKey,
      'anthropic-version': '2023-06-01'
    },
    body: JSON.stringify(body)
  })

  if (!resp.ok) {
    const text = await resp.text()
    throw new Error(`claude ${resp.status}: ${text.slice(0, 200)}`)
  }
  const json = await resp.json()
  const part = json.content?.find(p => p.type === 'text')
  return part?.text || '(空回复)'
}

module.exports = { chat }

// =============================================================
//  routes/messages.js
//  GET  /api/conversations/:id/messages   —— 拿对话历史
//  POST /api/conversations/:id/messages   —— 发用户消息 + 触发 AI 回复
// =============================================================

const express = require('express')
const db = require('../db')
const requireAuth = require('../middleware/requireAuth')
const llm = require('../llm')

const router = express.Router({ mergeParams: true })
router.use(requireAuth)

function getOwnedConv(convId, userId) {
  return db.prepare(
    'SELECT id, user_id, title FROM conversations WHERE id = ? AND user_id = ?'
  ).get(convId, userId)
}

// GET /api/conversations/:id/messages
router.get('/', (req, res) => {
  const conv = getOwnedConv(Number(req.params.id), req.user.id)
  if (!conv) return res.status(404).json({ message: '对话不存在' })

  const rows = db.prepare(
    'SELECT id, role, content, created_at FROM messages WHERE conversation_id = ? ORDER BY id ASC'
  ).all(conv.id)
  res.json(rows)
})

// POST /api/conversations/:id/messages   { content }
router.post('/', async (req, res) => {
  const conv = getOwnedConv(Number(req.params.id), req.user.id)
  if (!conv) return res.status(404).json({ message: '对话不存在' })

  const content = (req.body?.content || '').trim()
  if (!content) return res.status(400).json({ message: '消息内容不能为空' })

  const now = Date.now()
  const userMsgInfo = db.prepare(
    'INSERT INTO messages (conversation_id, role, content, created_at) VALUES (?, ?, ?, ?)'
  ).run(conv.id, 'user', content, now)
  const userMessage = {
    id: userMsgInfo.lastInsertRowid,
    role: 'user',
    content,
    created_at: now
  }

  // 如果对话还是默认标题，用首条用户消息前 20 字当标题
  if (conv.title === '新对话') {
    db.prepare('UPDATE conversations SET title = ?, updated_at = ? WHERE id = ?')
      .run(content.slice(0, 20), now, conv.id)
  } else {
    db.prepare('UPDATE conversations SET updated_at = ? WHERE id = ?').run(now, conv.id)
  }

  // 拼上下文喂给 LLM
  const history = db.prepare(
    'SELECT role, content FROM messages WHERE conversation_id = ? ORDER BY id ASC'
  ).all(conv.id)

  const settings = db.prepare(
    'SELECT provider, api_key, api_base, model, system_prompt FROM user_settings WHERE user_id = ?'
  ).get(req.user.id)

  let assistantContent
  try {
    assistantContent = await llm.generate({ settings, messages: history })
  } catch (e) {
    assistantContent = `⚠️ 调用 ${settings?.provider || 'mock'} 失败：${e.message}\n\n回到设置页检查 api_key / api_base 是否正确，或切回 mock 模式。`
  }

  const replyTime = Date.now()
  const aiInfo = db.prepare(
    'INSERT INTO messages (conversation_id, role, content, created_at) VALUES (?, ?, ?, ?)'
  ).run(conv.id, 'assistant', assistantContent, replyTime)

  db.prepare('UPDATE conversations SET updated_at = ? WHERE id = ?').run(replyTime, conv.id)

  res.status(201).json({
    user: userMessage,
    assistant: {
      id: aiInfo.lastInsertRowid,
      role: 'assistant',
      content: assistantContent,
      created_at: replyTime
    }
  })
})

module.exports = router

// =============================================================
//  routes/settings.js
//  当前用户的 LLM 设置（provider / api_key / api_base / model / system_prompt）
//  ⚠️ api_key 是敏感信息，响应里**不直接返回完整 key**，只返回 hasKey 标记
// =============================================================

const express = require('express')
const db = require('../db')
const requireAuth = require('../middleware/requireAuth')

const router = express.Router()
router.use(requireAuth)

const PROVIDERS = ['mock', 'openai', 'deepseek', 'claude']

function readSettings(userId) {
  return db.prepare(
    'SELECT user_id, provider, api_key, api_base, model, system_prompt, updated_at FROM user_settings WHERE user_id = ?'
  ).get(userId)
}

function publicView(row) {
  if (!row) return null
  return {
    provider:      row.provider,
    api_base:      row.api_base || '',
    model:         row.model || '',
    system_prompt: row.system_prompt || '',
    has_key:       !!(row.api_key && row.api_key.length > 0),
    // 只回显 key 的尾 4 位用于"已配置"提示
    key_tail:      row.api_key ? row.api_key.slice(-4) : '',
    updated_at:    row.updated_at
  }
}

// GET /api/settings
router.get('/', (req, res) => {
  let row = readSettings(req.user.id)
  if (!row) {
    // 极端情况：迁移/外部插入用户后没设置
    db.prepare(
      'INSERT INTO user_settings (user_id, provider, updated_at) VALUES (?, ?, ?)'
    ).run(req.user.id, 'mock', Date.now())
    row = readSettings(req.user.id)
  }
  res.json(publicView(row))
})

// PUT /api/settings   { provider, api_key?, api_base?, model?, system_prompt? }
//   api_key 不传 → 保留原值；传空字符串 → 清空
router.put('/', (req, res) => {
  const { provider, api_key, api_base, model, system_prompt } = req.body || {}

  if (provider && !PROVIDERS.includes(provider)) {
    return res.status(400).json({ message: `provider 只能是 ${PROVIDERS.join(' / ')}` })
  }

  const prev = readSettings(req.user.id) || {}
  const merged = {
    provider:      provider ?? prev.provider ?? 'mock',
    api_key:       api_key === undefined ? prev.api_key : api_key,
    api_base:      api_base ?? prev.api_base ?? '',
    model:         model ?? prev.model ?? '',
    system_prompt: system_prompt ?? prev.system_prompt ?? '',
    updated_at:    Date.now()
  }

  db.prepare(`
    INSERT INTO user_settings (user_id, provider, api_key, api_base, model, system_prompt, updated_at)
    VALUES (@user_id, @provider, @api_key, @api_base, @model, @system_prompt, @updated_at)
    ON CONFLICT(user_id) DO UPDATE SET
      provider      = excluded.provider,
      api_key       = excluded.api_key,
      api_base      = excluded.api_base,
      model         = excluded.model,
      system_prompt = excluded.system_prompt,
      updated_at    = excluded.updated_at
  `).run({ user_id: req.user.id, ...merged })

  res.json(publicView(readSettings(req.user.id)))
})

module.exports = router

// =============================================================
//  middleware/rateLimit.js
//  教学项目级别的限流：防爬虫、防爆破登录
//  生产环境建议接 Redis（这里用内存版方便教学）
// =============================================================

const rateLimit = require('express-rate-limit')

// 全局：每个 IP 每分钟最多 100 次请求
// （刷消息很正常，单值给宽松点；攻击者刷出量级会被拦）
exports.globalLimiter = rateLimit({
  windowMs: 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { message: '请求过于频繁，请稍后再试' }
})

// 登录/注册：每个 IP 每 5 分钟最多 20 次
// 防的是「拿字典爆破密码」「批量注册」
exports.authLimiter = rateLimit({
  windowMs: 5 * 60 * 1000,
  max: 20,
  standardHeaders: true,
  legacyHeaders: false,
  message: { message: '登录尝试过多，请 5 分钟后再试' }
})

// 发消息：每个用户每分钟最多 30 条
// 防的是「拿一个账号疯狂调 LLM 烧钱」「机器人灌水」
// 这里按 user.id 而不是 IP 分组（要求 requireAuth 在前面跑过）
exports.messageLimiter = rateLimit({
  windowMs: 60 * 1000,
  max: 30,
  standardHeaders: true,
  legacyHeaders: false,
  keyGenerator: (req) => req.user?.id?.toString() || req.ip,
  message: { message: '发送过于频繁，请稍等' }
})

